#include <Wire.h>
#include <LiquidCrystal_I2C.h>
#include <SPI.h>
#include <SD.h>
#define MR_PWM 9
#define SD_CS 8
#define ALARM_PIN 7
LiquidCrystal_I2C lcd(0x27,16,2);
File lg;
float intg=0,lastE=0;
float rmsB[32]; int rmsI=0;

float vibration_rms_window(float s,float*b,int*i,int n){
  b[(*i)%n]=s*s; (*i)++;
  float sum=0; for(int j=0;j<n;j++) sum+=b[j];
  return sqrtf(sum/n);
}
int pid_heater_control(float sp,float pv,float dt,float kp,float ki,float kd,float*ig,float*le){
  float e=sp-pv; *ig+=e*dt;
  float d=(e-*le)/(dt>0?dt:0.05f); *le=e;
  float o=kp*e+ki*(*ig)+kd*d;
  return constrain((int)o,0,255);
}

void init_hw(){
  Wire.begin(); lcd.init(); lcd.backlight();
  pinMode(MR_PWM,OUTPUT); analogWrite(MR_PWM,0);
  pinMode(ALARM_PIN,OUTPUT);
  SD.begin(SD_CS);
  lg=SD.open("vib.csv",FILE_WRITE);
  if(lg){lg.println("t,rms,pwm,fault");lg.close();}
}

float read_accel(){
  float raw=(analogRead(A0)*0.00488f-2.5f);
  return vibration_rms_window(raw,rmsB,&rmsI,32);
}

int compute_damper(float rms,float dt){
  int pwm=pid_heater_control(0.5f,rms,dt,80.0f,5.0f,2.0f,&intg,&lastE);
  analogWrite(MR_PWM,pwm); return pwm;
}

bool check_faults(float rms){
  bool f=(rms>2.5f);
  digitalWrite(ALARM_PIN,f); return f;
}

void log_status(float rms,int pwm,bool fault){
  lg=SD.open("vib.csv",FILE_WRITE);
  if(lg){lg.print(millis());lg.print(',');lg.print(rms,3);lg.print(',');lg.print(pwm);lg.print(',');lg.println(fault?1:0);lg.close();}
  lcd.setCursor(0,0);lcd.print("RMS:");lcd.print(rms,3);lcd.print("g ");
  lcd.setCursor(0,1);lcd.print("PWM:");lcd.print(pwm);lcd.print(fault?" FLT":"    ");
}

void setup(){Serial.begin(9600);init_hw();}
void loop(){
  static unsigned long lt=0;
  float dt=(millis()-lt)/1000.0f; if(dt<0.001f)dt=0.05f; lt=millis();
  float rms=read_accel();
  int pwm=compute_damper(rms,dt);
  bool fault=check_faults(rms);
  log_status(rms,pwm,fault);
  delay(50);
}
